// Service Worker for Santa Elena Platform
// Managed by Workbox via next-pwa

import { precacheAndRoute } from "workbox-precaching";
import { registerRoute } from "workbox-routing";
import { NetworkFirst, CacheFirst, StaleWhileRevalidate } from "workbox-strategies";
import { BackgroundSyncPlugin } from "workbox-background-sync";
import { ExpirationPlugin } from "workbox-expiration";

// Precache all assets generated by Next.js build
precacheAndRoute(self.__WB_MANIFEST || []);

// Background sync for offline actions
const bgSyncPlugin = new BackgroundSyncPlugin("offline-action-queue", {
  maxRetentionTime: 24 * 60, // 24 hours in minutes
});

// Cache API responses with NetworkFirst strategy
registerRoute(
  ({ url }) => url.pathname.startsWith("/api/v1/listings"),
  new NetworkFirst({
    cacheName: "api-listings",
    plugins: [
      new ExpirationPlugin({ maxEntries: 100, maxAgeSeconds: 5 * 60 }),
    ],
  })
);

// Cache static assets with CacheFirst
registerRoute(
  ({ request }) => request.destination === "image",
  new CacheFirst({
    cacheName: "images",
    plugins: [
      new ExpirationPlugin({ maxEntries: 200, maxAgeSeconds: 30 * 24 * 60 * 60 }),
    ],
  })
);

// Background sync for POST/PATCH/DELETE requests when offline
registerRoute(
  ({ request }) => ["POST", "PATCH", "DELETE"].includes(request.method),
  new NetworkFirst({
    plugins: [bgSyncPlugin],
  }),
  "POST"
);
